"""
modules/defi_analytics_engine.py — ProQuant Capital | Kripto & DeFi Analitik Merkezi v9.0
==========================================================================================
Merkeziyetsiz Finans (DeFi) dünyasının matematiksel dinamiklerini modeller.
Automated Market Maker (AMM) formülleri ( Constant Product: x*y=k ) ve 
Impermanent Loss (Kalıcı Olmayan Kayıp) hesaplamaları sunar.
Author: ProQuant Capital Digital Assets Unit | Version: 9.0.0
"""
import math

class DeFiAnalyticsEngine:
    def impermanent_loss(self, price_ratio: float) -> float:
        """Kalıcı Olmayan Kaybı hesaplar."""
        if price_ratio <= 0: return 1.0
        il = (2 * math.sqrt(price_ratio)) / (1 + price_ratio) - 1
        return abs(il)
        
    def amm_swap_output(self, reserve_in: float, reserve_out: float, amount_in: float, fee: float = 0.003) -> float:
        """Constant product (x*y=k) kuralına dayalı swap çıktısı."""
        amount_in_with_fee = amount_in * (1 - fee)
        numerator = amount_in_with_fee * reserve_out
        denominator = reserve_in + amount_in_with_fee
        return numerator / denominator

